#include<bits/stdc++.h>
using namespace std;

#define ll long long

ll n, t, v[1000001], w[1000100], dp[1000001], c, nd;

int main() {
	cin >> t >> n >> c;
	for (int i = 1; i <= n; i++) {
		cin >> v[i] >> w[i];
	}
	for (int i = 1; i <= n; i++) {
		for (int j = c; j >= w[i]; j--) {
			nd = dp[j];
			dp[j] = max(dp[j], dp[j - w[i]] + v[i]);
		}

	}
	for (int i = 0; i <= c; i++) {
		if (dp[i] >= t) {
			cout << c - i;
			return 0;
		}
	}
	cout << "Impossible";

	return 0;
}
